// HTTP/2 and HTTP/3 support constants (may not be in older SDKs)
// HTTP/2: Windows 10 1607+, HTTP/3: Windows 11 / Server 2022+
#ifndef WINHTTP_OPTION_ENABLE_HTTP_PROTOCOL
#define WINHTTP_OPTION_ENABLE_HTTP_PROTOCOL 133
#endif
#ifndef WINHTTP_OPTION_HTTP_PROTOCOL_USED
#define WINHTTP_OPTION_HTTP_PROTOCOL_USED 148
#endif
#ifndef WINHTTP_PROTOCOL_FLAG_HTTP2
#define WINHTTP_PROTOCOL_FLAG_HTTP2 0x1
#endif
// Note: HTTP/3 is defined for protocol detection only - NOT enabled for requests.
// HTTP/3 uses QUIC (UDP), which causes 10s timeouts on networks that block UDP.
// We explicitly enable only HTTP/2 in http_session_open(). This constant is used
// to detect if the server upgraded to HTTP/3 (for logging purposes only).
#ifndef WINHTTP_PROTOCOL_FLAG_HTTP3
#define WINHTTP_PROTOCOL_FLAG_HTTP3 0x2
#endif

