// Mock HTTP response structure
struct MockHttpResponse {
    DWORD status_code;
    char* body;
    size_t body_size;
    bool simulate_error;  // Return false from http_request
};

// Mock HTTP state - global for test control
struct MockHttpState {
    static constexpr size_t MAX_RESPONSES = 16;
    MockHttpResponse responses[MAX_RESPONSES];
    size_t response_count;
    size_t response_index;
    bool enabled;

    void reset() {
        for (size_t i = 0; i < response_count; i++) {
            delete[] responses[i].body;
        }
        memset(this, 0, sizeof(*this));
    }

    void queue_response(DWORD status, const char* body_data, size_t body_len) {
        if (response_count >= MAX_RESPONSES) return;
        MockHttpResponse& r = responses[response_count++];
        r.status_code = status;
        r.body = new char[body_len];
        memcpy(r.body, body_data, body_len);
        r.body_size = body_len;
        r.simulate_error = false;
    }

    void queue_error() {
        if (response_count >= MAX_RESPONSES) return;
        MockHttpResponse& r = responses[response_count++];
        r.status_code = 0;
        r.body = nullptr;
        r.body_size = 0;
        r.simulate_error = true;
    }

    MockHttpResponse* next() {
        if (response_index >= response_count) return nullptr;
        return &responses[response_index++];
    }
};

static MockHttpState g_mock_http;

#endif // GITSMARTER_TEST_BUILD

